import React, { useContext, useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip,
  ResponsiveContainer,
} from 'recharts';
import { AppCtx } from '../App';
import { fetchCosts, fetchCostByService, fetchCostSummary, fetchBudgets } from '../api/azure';
import PageHeader from '../components/PageHeader';
import AssetIcon from '../components/AssetIcon';
import { PAGE_ICONS } from '../config/assetIcons';
import { formatCurrency } from '../utils/format';
import { billingAmount, azureFieldLabel, formatChartAxis, DISPLAY_CURRENCY } from '../utils/costCurrency';

function parseCostRows(resp) {
  if (!resp) return [];
  const props = resp.properties || resp;
  const cols  = (props.columns || []).map(c => c.name);
  const rows  = props.rows || [];
  return rows.map(r => {
    const obj = {};
    cols.forEach((c, i) => { obj[c] = r[i]; });
    return obj;
  });
}

export default function CostExplorer() {
  const { subscription, billingCurrency } = useContext(AppCtx);
  const [timeframe, setTimeframe] = React.useState('MonthToDate');

  const { data: costData, isLoading: loadCost } = useQuery({
    queryKey: ['costs', subscription, timeframe],
    queryFn:  () => fetchCosts({ subscription_id: subscription, timeframe, granularity: 'Daily' }),
    enabled:  !!subscription,
  });

  const { data: summary, isLoading: loadSummary } = useQuery({
    queryKey: ['cost-summary', subscription, timeframe],
    queryFn:  () => fetchCostSummary({ subscription_id: subscription, timeframe }),
    enabled:  !!subscription,
  });

  const { data: svcData } = useQuery({
    queryKey: ['cost-by-svc', subscription, timeframe],
    queryFn:  () => fetchCostByService({ subscription_id: subscription, timeframe }),
    enabled:  !!subscription,
  });

  const { data: budgets } = useQuery({
    queryKey: ['budgets', subscription],
    queryFn:  () => fetchBudgets({ subscription_id: subscription }),
    enabled:  !!subscription,
  });

  const dailyRows = parseCostRows(costData?.data);
  const svcRows   = parseCostRows(svcData);

  const currency = billingCurrency || DISPLAY_CURRENCY;
  const fieldLabel = azureFieldLabel(currency);

  const dailyChart = dailyRows
    .filter(r => r.UsageDate || r.BillingPeriodStartDate)
    .map(r => ({
      date: String(r.UsageDate || r.BillingPeriodStartDate || '').slice(0, 10),
      cost: billingAmount(r),
    }))
    .sort((a, b) => a.date.localeCompare(b.date));

  const svcChart = svcRows
    .map(r => ({
      name: r.ServiceName || 'Other',
      cost: billingAmount(r),
    }))
    .sort((a, b) => b.cost - a.cost)
    .slice(0, 12);

  const total = useMemo(
    () => summary?.pretax_total ?? dailyChart.reduce((s, r) => s + r.cost, 0),
    [summary, dailyChart],
  );

  return (
    <div>
      <PageHeader
        title="Cost explorer"
        iconSrc={PAGE_ICONS.costs}
        subtitle={`Azure Cost Management · ${fieldLabel}`}
      >
        <select value={timeframe} onChange={e => setTimeframe(e.target.value)}>
          <option value="MonthToDate">Month to date</option>
          <option value="BillingMonthToDate">Billing month to date</option>
          <option value="TheLastMonth">Last month</option>
        </select>
      </PageHeader>

      {!subscription && <div className="card" style={{ textAlign: 'center', padding: '3rem', color: 'var(--text3)' }}>Select a subscription to view cost data.</div>}

      {subscription && (
        <>
          <div className="grid-4" style={{ marginBottom: '1.5rem' }}>
            <div className="stat-card accent">
              <AssetIcon src={PAGE_ICONS.costs} size={22} className="stat-card__icon" alt="" />
              <div className="stat-label">MTD spend ({currency})</div>
              <div className="stat-value">
                {loadSummary ? '…' : formatCurrency(total, { currency })}
              </div>
              <div className="stat-sub">{fieldLabel} · {timeframe}</div>
            </div>
            <div className="stat-card warning">
              <AssetIcon src={PAGE_ICONS.subscription} size={22} className="stat-card__icon" alt="" />
              <div className="stat-label">Budgets active</div>
              <div className="stat-value">{(budgets || []).length}</div>
              <div className="stat-sub">Configured budgets</div>
            </div>
            <div className="stat-card purple">
              <AssetIcon src={PAGE_ICONS.dashboard} size={22} className="stat-card__icon" alt="" />
              <div className="stat-label">Top service</div>
              <div className="stat-value" style={{ fontSize: '1rem', marginTop: 4 }}>{svcChart[0]?.name || '—'}</div>
              <div className="stat-sub">{formatCurrency(svcChart[0]?.cost || 0, { currency })}</div>
            </div>
            <div className="stat-card success">
              <AssetIcon src={PAGE_ICONS.costs} size={22} className="stat-card__icon" alt="" />
              <div className="stat-label">Services tracked</div>
              <div className="stat-value">{svcChart.length}</div>
              <div className="stat-sub">Top 12 by spend</div>
            </div>
          </div>

          <div className="card" style={{ marginBottom: '1.25rem' }}>
            <div style={{ fontWeight: 600, marginBottom: '1rem', fontSize: '0.9rem' }}>
              Daily cost ({currency}) · {timeframe}
            </div>
            {loadCost ? <div className="empty-state"><div className="spin" /></div> : dailyChart.length === 0 ? <div className="empty-state"><p>No daily cost data available.</p></div> : (
              <ResponsiveContainer width="100%" height={240}>
                <BarChart data={dailyChart}>
                  <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                  <XAxis dataKey="date" tick={{ fill: 'var(--text3)', fontSize: 11 }} />
                  <YAxis tick={{ fill: 'var(--text3)', fontSize: 11 }} tickFormatter={v => formatChartAxis(v, currency)} />
                  <Tooltip
                    contentStyle={{ background: 'var(--surface)', border: '1px solid var(--border)', borderRadius: 8 }}
                    formatter={(value) => [formatCurrency(value, { currency }), fieldLabel]}
                  />
                  <Bar dataKey="cost" name={fieldLabel} fill="#2563eb" radius={[3, 3, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            )}
          </div>

          <div className="card" style={{ marginBottom: '1.25rem' }}>
            <div style={{ fontWeight: 600, marginBottom: '1rem', fontSize: '0.9rem' }}>
              Cost by service ({currency})
            </div>
            {svcChart.length === 0 ? <div className="empty-state"><p>No service data.</p></div> : (
              <div className="table-wrap">
                <table>
                  <thead>
                    <tr>
                      <th>Service</th>
                      <th>{fieldLabel}</th>
                    </tr>
                  </thead>
                  <tbody>
                    {svcChart.map((row) => (
                      <tr key={row.name}>
                        <td style={{ color: 'var(--text)', fontWeight: 500 }}>{row.name}</td>
                        <td>{formatCurrency(row.cost, { currency })}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>

          {(budgets || []).length > 0 && (
            <div className="card">
              <div style={{ fontWeight: 600, marginBottom: '1rem', fontSize: '0.9rem' }}>Budgets</div>
              <div className="table-wrap">
                <table>
                  <thead><tr><th>Name</th><th>Amount</th><th>Current spend</th><th>Utilization</th></tr></thead>
                  <tbody>
                    {(budgets || []).map((b, i) => {
                      const p = b.properties || b;
                      const amt = p.amount || 0;
                      const cur = p.currentSpend?.amount ?? p.current_spend ?? 0;
                      const pct = amt > 0 ? Math.round((cur / amt) * 100) : 0;
                      const budgetCurrency = p.currency || currency;
                      return (
                        <tr key={b.id || i}>
                          <td style={{ color: 'var(--text)', fontWeight: 500 }}>{b.name || p.budget_name}</td>
                          <td>{formatCurrency(amt, { currency: budgetCurrency })}</td>
                          <td>{formatCurrency(parseFloat(cur), { currency: budgetCurrency })}</td>
                          <td>
                            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                              <div className="progress-bar-bg" style={{ flex: 1 }}>
                                <div className="progress-bar-fill" style={{ width: `${Math.min(pct, 100)}%`, background: pct > 95 ? 'var(--danger)' : pct > 80 ? 'var(--warning)' : 'var(--success)' }} />
                              </div>
                              <span style={{ fontSize: '0.8rem', minWidth: 36 }}>{pct}%</span>
                            </div>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </>
      )}
    </div>
  );
}
